 64‚Üí
 65‚Üí    private fun modifierEquals(keys: Binding.ModifierKeys?): Boolean {
 66‚Üí        // equals allowing subclasses
 67‚Üí        val thisKeys = binding.modifierKeys
 68‚Üí        if (thisKeys === keys) {
 69‚Üí            return true
 70‚Üí        }
 71‚Üí        // one is null
 72‚Üí        return if (keys == null || thisKeys == null) {
 73‚Üí            false
 74‚Üí        } else {
 75‚Üí            (thisKeys.shiftMatches(true) == keys.shiftMatches(true) || thisKeys.shiftMatches(false) == keys.shiftMatches(false)) &&
 76‚Üí                (thisKeys.ctrlMatches(true) == keys.ctrlMatches(true) || thisKeys.ctrlMatches(false) == keys.ctrlMatches(false)) &&
 77‚Üí                (thisKeys.altMatches(true) == keys.altMatches(true) || thisKeys.altMatches(false) == keys.altMatches(false))
 78‚Üí        }
 79‚Üí
 80‚Üí        // Perf: Could get a slight improvement if we check that both instances are not subclasses
 81‚Üí
 82‚Üí        // allow subclasses to work - a subclass which overrides shiftMatches will return true on one of the tests
