117‚Üí
118‚Üí            override fun toDisplayString(context: Context, binding: Binding): String {
119‚Üí                val formatString = when (side) {
120‚Üí                    CardSide.QUESTION -> context.getString(R.string.display_binding_card_side_question)
121‚Üí                    CardSide.ANSWER -> context.getString(R.string.display_binding_card_side_answer)
122‚Üí                    else -> context.getString(R.string.display_binding_card_side_both) // intentionally no prefix
