169‚Üí
170‚Üí        @Suppress("UNUSED_PARAMETER")
171‚Üí        @CheckResult
172‚Üí        fun fromString(s: String, v: Version = Version.ONE): MappableBinding? {
173‚Üí            if (s.isEmpty()) {
174‚Üí                return null
175‚Üí            }
176‚Üí            return try {
177‚Üí                // the prefix of the serialized
178‚Üí                when (s[0]) {
179‚Üí                    'r' -> Screen.Reviewer.fromString(s.substring(1))
180‚Üí                    else -> null
181‚Üí                }
182‚Üí            } catch (e: Exception) {
183‚Üí                Timber.w(e, "failed to deserialize binding")
