187‚Üí
188‚Üí        @CheckResult
189‚Üí        fun fromPreferenceString(string: String?): MutableList<MappableBinding> {
190‚Üí            if (string.isNullOrEmpty()) return ArrayList()
191‚Üí            try {
192‚Üí                val version = string.takeWhile { x -> x != '/' }
193‚Üí                val remainder = string.substring(version.length + 1) // skip the /
194‚Üí                if (version != "1") {
195‚Üí                    Timber.w("cannot handle version '$version'")
196‚Üí                    return ArrayList()
197‚Üí                }
198‚Üí                return remainder.split(PREF_SEPARATOR).mapNotNull { fromString(it) }.toMutableList()
199‚Üí            } catch (e: Exception) {
200‚Üí                Timber.w(e, "Failed to deserialize preference")
