29‚Üí/** Accepts peripheral input, mapping via various keybinding strategies,
30‚Üí * and converting them to commands for the Reviewer.  */
31‚Üíclass PeripheralKeymap(reviewerUi: ReviewerUi, commandProcessor: ViewerCommand.CommandProcessor) {
32‚Üí    private val mKeyMap: KeyMap
33‚Üí    private var mHasSetup = false
34‚Üí    fun setup() {
35‚Üí        val preferences = AnkiDroidApp.instance.sharedPrefs()
36‚Üí        setup(preferences)
37‚Üí    }
38‚Üí
39‚Üí    fun setup(preferences: SharedPreferences) {
40‚Üí        for (command in ViewerCommand.values()) {
41‚Üí            add(command, preferences)
42‚Üí        }
43‚Üí        mHasSetup = true
44‚Üí    }
45‚Üí
46‚Üí    private fun add(command: ViewerCommand, preferences: SharedPreferences) {
47‚Üí        val bindings: MutableList<MappableBinding> = fromPreference(preferences, command)
48‚Üí        for (b in bindings) {
49‚Üí            if (!b.isKey) {
50‚Üí                continue
51‚Üí            }
52‚Üí            mKeyMap[b] = command
53‚Üí        }
54‚Üí    }
55‚Üí
56‚Üí    fun onKeyDown(keyCode: Int, event: KeyEvent): Boolean {
57‚Üí        return if (!mHasSetup || event.repeatCount > 0) {
58‚Üí            false
59‚Üí        } else {
60‚Üí            mKeyMap.onKeyUp(keyCode, event)
61‚Üí        }
62‚Üí    }
63‚Üí
64‚Üí    @Suppress("UNUSED_PARAMETER")
65‚Üí    fun onKeyUp(keyCode: Int, event: KeyEvent?): Boolean {
66‚Üí        return false
67‚Üí    }
68‚Üí
69‚Üí    class KeyMap(private val processor: ViewerCommand.CommandProcessor, private val reviewerUI: ReviewerUi) {
70‚Üí        val mBindingMap = HashMap<MappableBinding, ViewerCommand>()
71‚Üí
72‚Üí        @Suppress("UNUSED_PARAMETER")
73‚Üí        fun onKeyUp(keyCode: Int, event: KeyEvent?): Boolean {
74‚Üí            var ret = false
75‚Üí            val bindings = key(event!!)
76‚Üí            val side = fromAnswer(reviewerUI.isDisplayingAnswer)
77‚Üí            for (b in bindings) {
78‚Üí                val binding = MappableBinding(b, MappableBinding.Screen.Reviewer(side))
79‚Üí                val command = mBindingMap[binding] ?: continue
80‚Üí                ret = ret or processor.executeCommand(command, fromGesture = null)
81‚Üí            }
82‚Üí            return ret
83‚Üí        }
84‚Üí
85‚Üí        operator fun set(key: MappableBinding, value: ViewerCommand) {
86‚Üí            mBindingMap[key] = value
87‚Üí        }
88‚Üí
89‚Üí        operator fun get(key: MappableBinding): ViewerCommand? {
90‚Üí            return mBindingMap[key]
91‚Üí        }
92‚Üí    }
93‚Üí
94‚Üí    init {
95‚Üí        mKeyMap = KeyMap(commandProcessor, reviewerUi)
96‚Üí    }
97‚Üí}
